"""
Implementation of all DSL operators for the Factor Lab.

Three categories:
  1. Time-series  — applied per-stock (groupby symbol, along the time axis)
  2. Cross-sectional — applied per-date (groupby date, across all stocks)
  3. Universal — element-wise or simple transforms
"""

from __future__ import annotations

import numpy as np
import pandas as pd


# ===========================================================================
# Time-series operators  (per-stock, along time axis)
# ===========================================================================

def ts_mean(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).mean()


def ts_std(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).std(ddof=1)


def ts_max(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).max()


def ts_min(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).min()


def ts_sum(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).sum()


def ts_rank(x: pd.Series, n: int) -> pd.Series:
    """Percentile rank of the current value within the last *n* values."""
    def _pct_rank(arr: np.ndarray) -> float:
        if np.isnan(arr[-1]):
            return np.nan
        valid = arr[~np.isnan(arr)]
        if len(valid) < 2:
            return np.nan
        return (valid < arr[-1]).sum() / (len(valid) - 1)

    return x.rolling(n, min_periods=n).apply(_pct_rank, raw=True)


def ts_argmax(x: pd.Series, n: int) -> pd.Series:
    """Days since the max within the last *n* values (0 = today)."""
    def _argmax(arr: np.ndarray) -> float:
        if np.any(np.isnan(arr)):
            return np.nan
        return float(len(arr) - 1 - np.argmax(arr))

    return x.rolling(n, min_periods=n).apply(_argmax, raw=True)


def ts_argmin(x: pd.Series, n: int) -> pd.Series:
    """Days since the min within the last *n* values (0 = today)."""
    def _argmin(arr: np.ndarray) -> float:
        if np.any(np.isnan(arr)):
            return np.nan
        return float(len(arr) - 1 - np.argmin(arr))

    return x.rolling(n, min_periods=n).apply(_argmin, raw=True)


def ts_corr(x: pd.Series, y: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).corr(y)


def ts_cov(x: pd.Series, y: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).cov(y)


def ts_count(s: pd.Series, n: int) -> pd.Series:
    """Count of positive (> 0) values in the last *n* periods."""
    return (s > 0).astype(float).rolling(int(n), min_periods=1).sum()


def ts_skew(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).skew()


def ts_kurt(x: pd.Series, n: int) -> pd.Series:
    return x.rolling(n, min_periods=n).kurt()


def ts_product(x: pd.Series, n: int) -> pd.Series:
    """Rolling product over the last *n* values."""
    return x.rolling(n, min_periods=n).apply(np.prod, raw=True)


def delta(x: pd.Series, n: int) -> pd.Series:
    """x[t] - x[t - n]."""
    return x - x.shift(n)


def pct_change(x: pd.Series, n: int) -> pd.Series:
    """(x[t] / x[t - n]) - 1, guarded against division by zero."""
    prev = x.shift(n)
    return (x / prev.replace(0, np.nan)) - 1


def shift(x: pd.Series, n: int) -> pd.Series:
    """Lag by *n* periods."""
    return x.shift(n)


def decay_linear(x: pd.Series, n: int) -> pd.Series:
    """Linearly-weighted moving average: weight_i = i / sum(1..n)."""
    weights = np.arange(1, n + 1, dtype=float)
    weights /= weights.sum()

    def _wma(arr: np.ndarray) -> float:
        if np.any(np.isnan(arr)):
            return np.nan
        return float(np.dot(arr, weights))

    return x.rolling(n, min_periods=n).apply(_wma, raw=True)


def decay_exp(x: pd.Series, n: int) -> pd.Series:
    """Exponentially-weighted moving average with half-life = *n*."""
    return x.ewm(halflife=n, min_periods=n).mean()


# ===========================================================================
# Cross-sectional operators  (per-date, across all stocks)
# ===========================================================================

def rank(x: pd.Series) -> pd.Series:
    """Cross-sectional percentile rank in [0, 1]."""
    return x.rank(pct=True)


def zscore(x: pd.Series) -> pd.Series:
    """Cross-sectional z-score."""
    mu = x.mean()
    sigma = x.std(ddof=1)
    if sigma == 0 or np.isnan(sigma):
        return x * 0.0  # all same → zero
    return (x - mu) / sigma


def demean(x: pd.Series) -> pd.Series:
    """Subtract cross-sectional mean."""
    return x - x.mean()


# ===========================================================================
# Universal operators  (element-wise)
# ===========================================================================

def op_abs(x: pd.Series) -> pd.Series:
    return x.abs()


def sign(x: pd.Series) -> pd.Series:
    return np.sign(x)


def log(x: pd.Series) -> pd.Series:
    """Natural log, guarded: log(x) where x <= 0 → NaN."""
    return np.log(x.where(x > 0, np.nan))


def sqrt(x: pd.Series) -> pd.Series:
    """Square root, guarded: negative values → NaN."""
    return np.sqrt(x.where(x >= 0, np.nan))


def power(x: pd.Series, p: float) -> pd.Series:
    return x ** p


def clamp(x: pd.Series, lo: float, hi: float) -> pd.Series:
    return x.clip(lower=lo, upper=hi)


def op_max(x: pd.Series, y: pd.Series) -> pd.Series:
    """Element-wise max of two series."""
    return pd.concat([x, y], axis=1).max(axis=1)


def op_min(x: pd.Series, y: pd.Series) -> pd.Series:
    """Element-wise min of two series."""
    return pd.concat([x, y], axis=1).min(axis=1)


def if_then(cond: pd.Series, a: pd.Series, b: pd.Series) -> pd.Series:
    """Where cond > 0, return a; otherwise b."""
    return a.where(cond > 0, b)


# ===========================================================================
# Operator registry (name → callable)
# ===========================================================================

# Maps DSL function name to (callable, operator_type).
# operator_type: "ts" = time-series, "cs" = cross-sectional, "univ" = universal.

OPERATOR_REGISTRY: dict[str, tuple[callable, str]] = {
    # time-series
    "ts_mean":      (ts_mean, "ts"),
    "ts_std":       (ts_std, "ts"),
    "ts_max":       (ts_max, "ts"),
    "ts_min":       (ts_min, "ts"),
    "ts_sum":       (ts_sum, "ts"),
    "ts_rank":      (ts_rank, "ts"),
    "ts_argmax":    (ts_argmax, "ts"),
    "ts_argmin":    (ts_argmin, "ts"),
    "ts_corr":      (ts_corr, "ts"),
    "ts_cov":       (ts_cov, "ts"),
    "ts_count":     (ts_count, "ts"),
    "ts_skew":      (ts_skew, "ts"),
    "ts_kurt":      (ts_kurt, "ts"),
    "ts_product":   (ts_product, "ts"),
    "delta":        (delta, "ts"),
    "pct_change":   (pct_change, "ts"),
    "shift":        (shift, "ts"),
    "decay_linear": (decay_linear, "ts"),
    "decay_exp":    (decay_exp, "ts"),
    # cross-sectional
    "rank":         (rank, "cs"),
    "zscore":       (zscore, "cs"),
    "demean":       (demean, "cs"),
    # universal
    "abs":          (op_abs, "univ"),
    "sign":         (sign, "univ"),
    "log":          (log, "univ"),
    "sqrt":         (sqrt, "univ"),
    "power":        (power, "univ"),
    "clamp":        (clamp, "univ"),
    "max":          (op_max, "univ"),
    "min":          (op_min, "univ"),
    "if_then":      (if_then, "univ"),
}

"""
Factor computation engine — executes an AST against a price DataFrame.

Usage
-----
>>> from src.dsl.parser import parse
>>> from src.dsl.compute import compute_factor
>>> ast = parse("rank(delta(close, 5))")
>>> result = compute_factor(ast, prices_df)
# result: DataFrame with [sym_col, date_col, "factor_value"]
"""

from __future__ import annotations

from typing import Callable

import numpy as np
import pandas as pd

from src.dsl.parser import (
    ASTNode,
    BinOp,
    DSLParseError,
    Feature,
    FunctionCall,
    Literal,
    UnaryOp,
)
from src.dsl.operators import OPERATOR_REGISTRY


# ---------------------------------------------------------------------------
# Feature resolver
# ---------------------------------------------------------------------------

# Canonical feature name  →  list of possible column names (first match wins).
_FEATURE_ALIASES: dict[str, list[str]] = {
    "close":         ["close", "Close", "adj_close"],
    "open":          ["open", "Open"],
    "high":          ["high", "High"],
    "low":           ["low", "Low"],
    "volume":        ["volume", "vol", "Volume"],
    "amount":        ["amount", "Amount", "turnover"],
    "vwap":          ["vwap", "VWAP"],
    "turnover_rate": ["turnover_rate", "turnover"],
}

# Features that can be computed on the fly from base columns.
_COMPUTED_FEATURES: dict[str, Callable[[pd.DataFrame, str, str], pd.Series]] = {
    "ret_1d": lambda df, sym, dt: df.groupby(sym)["close"].pct_change(1),
    "ret_5d": lambda df, sym, dt: df.groupby(sym)["close"].pct_change(5),
    "ret_20d": lambda df, sym, dt: df.groupby(sym)["close"].pct_change(20),
    "volume_ratio": lambda df, sym, dt: (
        df["volume"] / df.groupby(sym)["volume"].transform(
            lambda s: s.rolling(20, min_periods=1).mean()
        )
    ),
}


def _resolve_feature(
    name: str,
    prices_df: pd.DataFrame,
    sym_col: str,
    date_col: str,
) -> pd.Series:
    """Return a pd.Series aligned to *prices_df* for the given feature name."""

    # 1. Check aliases (direct column lookup)
    candidates = _FEATURE_ALIASES.get(name)
    if candidates:
        for col in candidates:
            if col in prices_df.columns:
                return prices_df[col].copy()

    # 2. Computed features
    if name in _COMPUTED_FEATURES:
        return _COMPUTED_FEATURES[name](prices_df, sym_col, date_col)

    # 3. Exact column match (for arbitrary features like rsi_14, pe_ttm, etc.)
    if name in prices_df.columns:
        return prices_df[name].copy()

    # 4. Try vwap = amount / volume if vwap requested but not present
    if name == "vwap":
        if "amount" in prices_df.columns and "volume" in prices_df.columns:
            vol = prices_df["volume"].replace(0, np.nan)
            return prices_df["amount"] / vol

    raise DSLParseError(
        f"Feature {name!r} not found in DataFrame columns: "
        f"{sorted(prices_df.columns.tolist())}"
    )


# ---------------------------------------------------------------------------
# AST evaluator
# ---------------------------------------------------------------------------

class _Evaluator:
    """
    Walks the AST and produces a pd.Series of factor values,
    aligned to the index of *prices_df*.

    Strategy:
      - Leaf Feature → column lookup / compute
      - Leaf Literal  → scalar (broadcast when needed)
      - FunctionCall  → dispatch via OPERATOR_REGISTRY
        * ts operators → groupby(sym_col).transform(...)
        * cs operators → groupby(date_col).transform(...)
        * univ operators → element-wise
      - BinOp → numpy vectorised arithmetic
      - UnaryOp → negation
    """

    def __init__(
        self,
        prices_df: pd.DataFrame,
        sym_col: str,
        date_col: str,
    ) -> None:
        self.df = prices_df
        self.sym_col = sym_col
        self.date_col = date_col

        # Cache resolved features to avoid repeated computation.
        self._cache: dict[str, pd.Series] = {}

    # -- public entry --------------------------------------------------------

    def evaluate(self, node: ASTNode) -> pd.Series:
        if isinstance(node, Literal):
            return self._eval_literal(node)
        if isinstance(node, Feature):
            return self._eval_feature(node)
        if isinstance(node, UnaryOp):
            return self._eval_unary(node)
        if isinstance(node, BinOp):
            return self._eval_binop(node)
        if isinstance(node, FunctionCall):
            return self._eval_call(node)
        raise DSLParseError(f"Cannot evaluate node type: {type(node)}")

    # -- leaf nodes ----------------------------------------------------------

    def _eval_literal(self, node: Literal) -> pd.Series:
        return pd.Series(node.value, index=self.df.index, dtype=float)

    def _eval_feature(self, node: Feature) -> pd.Series:
        name = node.name
        if name not in self._cache:
            self._cache[name] = _resolve_feature(
                name, self.df, self.sym_col, self.date_col
            )
        return self._cache[name].copy()

    # -- operators -----------------------------------------------------------

    def _eval_unary(self, node: UnaryOp) -> pd.Series:
        child = self.evaluate(node.operand)
        if node.op == "-":
            return -child
        raise DSLParseError(f"Unknown unary operator: {node.op!r}")

    def _eval_binop(self, node: BinOp) -> pd.Series:
        left = self.evaluate(node.left)
        right = self.evaluate(node.right)
        if node.op == "+":
            return left + right
        if node.op == "-":
            return left - right
        if node.op == "*":
            return left * right
        if node.op == "/":
            return left / right.replace(0, np.nan)
        raise DSLParseError(f"Unknown binary operator: {node.op!r}")

    def _eval_call(self, node: FunctionCall) -> pd.Series:
        entry = OPERATOR_REGISTRY.get(node.name)
        if entry is None:
            raise DSLParseError(f"No implementation for function: {node.name!r}")

        func, op_type = entry

        # Evaluate all argument sub-trees first.
        evaluated_args = [self.evaluate(a) for a in node.args]

        if op_type == "ts":
            return self._apply_ts(func, evaluated_args, node.name)
        elif op_type == "cs":
            return self._apply_cs(func, evaluated_args, node.name)
        else:  # "univ"
            return self._apply_univ(func, evaluated_args, node.name)

    # -- dispatch helpers ----------------------------------------------------

    def _apply_ts(
        self,
        func: Callable,
        args: list[pd.Series],
        name: str,
    ) -> pd.Series:
        """
        Time-series operator: apply *func* per stock (groupby sym_col).

        The last argument is always the window (int scalar extracted from the
        constant Literal that the parser already validated).
        """
        window = int(args[-1].iloc[0])  # constant series → scalar
        series_args = args[:-1]

        sym = self.df[self.sym_col]

        if len(series_args) == 1:
            # Single-series ts operator: ts_mean(x, n), delta(x, n), etc.
            x = series_args[0]
            return x.groupby(sym, group_keys=False).transform(
                lambda s: func(s, window)
            )
        elif len(series_args) == 2:
            # Two-series ts operator: ts_corr(x, y, n), ts_cov(x, y, n)
            x, y = series_args
            # Must group both in lockstep
            result = pd.Series(np.nan, index=self.df.index, dtype=float)
            for key, idx in x.groupby(sym).groups.items():
                sx = x.loc[idx]
                sy = y.loc[idx]
                result.loc[idx] = func(sx, sy, window).values
            return result
        else:
            raise DSLParseError(
                f"Time-series function {name!r} got unexpected number of "
                f"series arguments: {len(series_args)}"
            )

    def _apply_cs(
        self,
        func: Callable,
        args: list[pd.Series],
        name: str,
    ) -> pd.Series:
        """Cross-sectional operator: apply *func* per date (groupby date_col)."""
        x = args[0]
